1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote (premium)", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (processing fee only)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, { op: "quote", items: [] }, 0)).toBe(5);
8	  });
9	
10	  // --- Single main item base premiums (+ fee, first insurance per item) ---
11	  // Newcomer, single plain item: base + 10% first insurance + 5 fee.
12	  it.todo("single sword (newcomer) → 100 + 10 first + 5 fee = 115 G");
13	  it.todo("single amulet (newcomer) → 60 + 6 first + 5 fee = 71 G");
14	  it.todo("single staff (newcomer) → 80 + 8 first + 5 fee = 93 G");
15	  it.todo("single potion (newcomer) → 40 + 4 first + 5 fee = 49 G");
16	
17	  // --- Components and building blocks (base premiums per spec examples) ---
18	  it.todo("1 rune → base premium 25 G");
19	  it.todo("2 runes → base premium 50 G");
20	  it.todo("3 runes → base premium 60 G (block applies)");
21	  it.todo("4 runes → base premium 100 G (no block — block requires exactly 3)");
22	  it.todo("7 runes → base premium 175 G");
23	
24	  // --- "Alike" components (❓ resolved: alike = same type) ---
25	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
26	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
27	
28	  // --- Item-specific modifiers in isolation ---
29	  it.todo("cursed sword → base 100 + 50% curse surcharge on the item");
30	  it.todo("sword enchantment 5 → +30% high-enchantment surcharge (threshold inclusive)");
31	  it.todo("sword enchantment 4 → no high-enchantment surcharge");
32	  it.todo("sword enchantment 5 and cursed → both surcharges apply");
33	
34	  // --- Policy-wide modifiers in isolation ---
35	  it.todo("loyalty: customer with exactly 2 years → 20% loyalty discount applies");
36	  it.todo("follow-up: second+ quote in scenario → 15% follow-up discount applies");
37	
38	  // --- Modifier scope on multi-item policies (❓ resolved) ---
39	  it.todo("cursed sword + plain amulet → policy base 160, curse adds 50 (on sword only) → 210 before fee/policy modifiers");
40	
41	  // --- Rounding (MHPCO's favor) ---
42	  it.todo("premium yielding 197.5 → rounded UP to 198 G");
43	
44	  // --- Integration examples ---
45	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
46	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → premium 160 G");
47	});
