49	describe("MHPCO Claim Office — claim (payout)", () => {
50	  // --- Standard reimbursement (no special clauses) ---
51	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 G (500 − 100 deductible)");
52	  it.todo("rune (value 250), damage 200 → payout 100 G (200 − 100, no special clause)");
53	
54	  // --- Enchantment threshold vs dragon material ---
55	  it.todo("dragon sword, ench 8, damage 1000 → payout 400 G (50% then deductible)");
56	  it.todo("dragon sword, ench 9, damage 1000 → payout 400 G (50% wins, then deductible)");
57	  it.todo("dragon sword, ench 5, damage 800 → payout 700 G (dragon full, then deductible)");
58	  it.todo("steel sword, ench 9, damage 1000 → payout 400 G (50% then deductible)");
59	
60	  // --- Deductible per damage event ---
61	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
62	
63	  // --- Multiple items of the same type ---
64	  it.todo("two swords insured → insurance sum 2000, two sword damages each get own deductible");
65	  it.todo("more sword damages than swords insured → claim rejected (error)");
66	
67	  // --- Cap exhaustion across successive claims ---
68	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remainingCap 600");
69	  it.todo("sword (cap 2000): second claim 1500 → payout 600, remainingCap 0 (reduced to remaining cap)");
70	
71	  // --- Cap basis ---
72	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value; premium modifiers do not raise cap)");
73	  it.todo("sword + 3 runes (block) → insurance sum 1750 (block discount does not affect insurance sum)");
74	
75	  // --- Rounding (payout rounded down) ---
76	  it.todo("payout yielding 350.5 → rounded DOWN to 350 G");
77	
78	  // --- Claim error cases ---
79	  it.todo("damage to item not in policy → claim rejected (error)");
80	  it.todo("damage with negative amount → claim rejected (error)");
81	});
82	
